// gen-playground-bundle.mjs — bundle the Holo Playground runtime into ONE self-contained IIFE and emit it as
// a C++ raw-string header the host ExecuteJavaScript()s into every real web page's main world (CSP-proof:
// a holo:// <script> is refused by sites like HN/Google; host V8 execution is not subject to page CSP).
//
//   node tools/gen-playground-bundle.mjs
//
// Reuses the repo's installed esbuild. Entry = holo-playground-web-boot.js (imports the 8 deps + runs as an
// IIFE side-effect). Output = src/playground_bundle.h with `const char kHoloPlaygroundBundle[]`.

import { execFileSync } from "node:child_process";
import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const here = dirname(fileURLToPath(import.meta.url));
const repo = join(here, "..", "..", "..", "..", "..");                 // …/HOLOGRAM
// Invoke the real esbuild binary, not the .bin shim: Node 20+/22 reject execFileSync of a .cmd/.bat
// without shell:true (EINVAL), so on Windows go straight to the native @esbuild/win32-* esbuild.exe.
const esbuild = process.platform === "win32"
  ? join(repo, ".ui-build", "node_modules", "@esbuild", "win32-" + (process.arch === "arm64" ? "arm64" : "x64"), "esbuild.exe")
  : join(repo, ".ui-build", "node_modules", ".bin", "esbuild");
const entry = join(repo, "holo-os", "system", "os", "usr", "lib", "holo", "holo-playground-web-boot.js");
const outJs = join(here, "holo-pg-bundle.gen.js");
const outH = join(here, "..", "src", "playground_bundle.h");

if (!existsSync(esbuild)) throw new Error("esbuild not found at " + esbuild);
execFileSync(esbuild, [entry, "--bundle", "--format=iife", "--minify", "--legal-comments=none", "--outfile=" + outJs], { stdio: "inherit" });

const js = readFileSync(outJs, "utf8");
if (/import\s*\(/.test(js) || /holo:\/\/os\/_shared/.test(js)) throw new Error("bundle is NOT self-contained (has dynamic import / holo:// ref)");
const D = "HOLOPGBUNDLE";
if (js.includes(")" + D + '"')) throw new Error("raw-string delimiter clash");

// MSVC caps a SINGLE string literal at 16380 bytes (error C2026 "string too big"). The bundle is ~46 KB, so
// emit it as multiple ADJACENT raw-string literals — the C++ compiler concatenates adjacent literals into one
// array. Chunk at <=12000 UTF-8 bytes, never splitting a code point (so multi-byte chars stay intact).
const MAX_BYTES = 12000;
const chunks = [];
let cur = "", curBytes = 0;
for (const ch of js) {                                   // string iteration yields whole code points (no surrogate split)
  const b = Buffer.byteLength(ch, "utf8");
  if (curBytes + b > MAX_BYTES && cur) { chunks.push(cur); cur = ""; curBytes = 0; }
  cur += ch; curBytes += b;
}
if (cur) chunks.push(cur);
for (const c of chunks) {                                // belt-and-suspenders: each literal must clear the C2026 limit
  if (Buffer.byteLength(c, "utf8") > 16000) throw new Error("chunk exceeds MSVC literal limit");
}
const body = chunks.map((c) => 'R"' + D + "(" + c + ")" + D + '"').join("\n");

const banner = [
  "// playground_bundle.h - GENERATED by tools/gen-playground-bundle.mjs. Do not edit by hand.",
  "// The full Holo Playground runtime as ONE self-contained IIFE (esbuild bundle of holo-playground-web-boot.js",
  "// + its 8 deps; no import/fetch). app.cc ExecuteJavaScript()s it into every real web page's MAIN WORLD, which",
  "// BYPASSES the page CSP (a holo:// <script> is refused by sites like HN/Google; host V8 exec is not CSP-gated).",
  "// Split into adjacent raw-string chunks (<=12 KB each); a single literal would trip MSVC C2026 (16380-byte cap).",
  "#ifndef HOLO_PLAYGROUND_BUNDLE_H",
  "#define HOLO_PLAYGROUND_BUNDLE_H",
  "const char kHoloPlaygroundBundle[] =",
].join("\n");
writeFileSync(outH, banner + "\n" + body + ";\n#endif\n");
console.log("wrote " + outH + " (" + js.length + " bytes of JS in " + chunks.length + " literals)");
